let _timeOutFunc: Function = setTimeout;


export interface DateProvider {
	getDate: () => Date;
}


export class DefaultDateProvider implements DateProvider {

	getDate() {
		return new Date();
	}
}


export interface TimelineElement {
	timeMs: number;
	action: Function;
}


// wanted to use TS enums, but can't get them to work as strings in JS
export const PartOfDay = {
	MORNING: 'MORNING',
	AFTERNOON: 'AFTERNOON',
	EVENING: 'EVENING',
	NIGHT: 'NIGHT'
};


export class TimeUtils {

	/**
	 * A class that can provide dates (defaults to `new Date()`)
	 * @type {DateProvider}
	 * @private
	 */
	static _dateProvider: DateProvider = new DefaultDateProvider();

	/**
	 * Sets the date provider that should be used by TimeUtils
	 * @param {DateProvider} dateProvider
	 */
	static setDateProvider(dateProvider: DateProvider) {
		TimeUtils._dateProvider = dateProvider;
	}

	/**
	 * Provide the timeout function to use in all time utilities
	 * @param {Function.<Function, number>} timeoutFunc
	 */
	static setTimeoutFunction(timeoutFunc: Function) {
		_timeOutFunc = timeoutFunc;
	}

	/**
	 * Waits for timeMs and then resolves the promise
	 * @param {number} timeMs Time to wait in ms
	 * @returns {Promise<void>}
	 */
	static async wait(timeMs: number): Promise<any> {
		return new Promise( (res) => {
			_timeOutFunc(res, timeMs);
		});
	}

	/**
	 * Dispatch a timeline of actions
	 * @param {TimelineElement[]} timeline
	 * @returns {Promise<void>}
	 */
	static async dispatchTimeline(timeline: TimelineElement[]): Promise<any> {
		let startTime = process.hrtime();

		let promiseChain = Promise.resolve();
		timeline.forEach( el => {
			promiseChain = promiseChain
				.then( () => TimeUtils._dispatchTimeline(el, startTime) );
		});

		return promiseChain;
	}

	static async _dispatchTimeline(el: TimelineElement, startTime: number[]): Promise<any> {
		let timeDiff = process.hrtime(startTime);
		let passedTimeMs = timeDiff[0] * 1e3 + timeDiff[1] * 1e-6;

		let timeToWait = Math.max(0, el.timeMs - passedTimeMs);
		return TimeUtils.wait(timeToWait).then( () => el.action() );
	}

	/**
	 * returns the current part of day (morning, afternoon, evening, night)
	 * @param {Date} [date] Optional date, defaults to using date provider
	 * @returns {PartOfDay}
	 */
	static getPartOfDay(date?: Date) {
		date = date || TimeUtils._dateProvider.getDate();
		let hours = date.getHours();
		if (hours > 5 && hours < 12) {
			return PartOfDay.MORNING;
		}
		else if (hours < 18) {
			return PartOfDay.AFTERNOON;
		}
		else if (hours < 23) {
			return PartOfDay.EVENING;
		}
		else {
			return PartOfDay.NIGHT;
		}
	}

	/**
	 * Returns whether it is early in the morning (between 5 and 7 am)
	 * @param {Date} [date] Optional date, defaults to using date provider
	 * @returns {boolean}
	 */
	static isEarlyMorning(date?: Date) {
		date = date || TimeUtils._dateProvider.getDate();

		return (TimeUtils.getPartOfDay(date) === PartOfDay.MORNING) && (date.getHours() < 7);
	}

}

