import * as events from 'events';
import * as path from 'path';


class MockDOFSet {

	private _dofs: Set<string>;

	constructor(dofs: string[]) {
		this._dofs = new Set(dofs);
	}

	hasDOF(name: string): boolean {
		return this._dofs.has(name);
	}
}

export interface DOFOptions {
    allOrNothing: boolean;
}

export interface KeysPlaybackOptions {
	jibo: any;
	animPath?: string;
	assetPack?: string;
	animData?: any;
	rootPath?: string;
	cache?: string;
	configBuilder?: Function;
	handleAnimation?: Function;
	screenCenterOverride?: boolean;
	overrideDestroy?: boolean;
	overrideUnload?: boolean;
	ownerInformation?: string;
	dofOptions?: DOFOptions;
}

export class KeysPlayback extends events.EventEmitter {

	private _instance: any;
	private _hasScreenDOFs: boolean;
	private _resolver: Function;

	constructor(private _animation: any,
		    private _cache: string,
		    private _alias: string,
		    private _options: KeysPlaybackOptions) {
		super();

		this._animation.on('EVENT', (event, instance, payload) => {
			this.emit(event, instance, payload);
		});
	}

	/**
	 * Starts playing animation
	 * @param {Function} [configBuilder] Configure animation builder
	 * @param {Function} [handleAnimation] Returns the animation created by `builder.play()`
	 * @param {boolean} [screenCenterOverride] Override the default behavior of
	 * centering screen dofs before playing an animation that has any screen content
	 * @deprecated
	 * @returns {Promise}
	 */
	async play(configBuilder?: Function, handleAnimation?: Function, screenCenterOverride?: boolean): Promise<any>;
	/**
	 * Starts playing animation
	 * @returns {Promise}
	 */
	async play(): Promise<any>;
	async play(arg1?: any, arg2?: any, arg3?: any): Promise<any> {
		this._options.configBuilder = arg1 || this._options.configBuilder;
		this._options.handleAnimation = arg2 || this._options.handleAnimation;
		this._options.screenCenterOverride = (typeof arg3 === 'boolean') ? arg3 : this._options.screenCenterOverride;

		const jibo = this._options.jibo;

		return new Promise( resolve => {
			this._resolver = resolve;
			let hasBeenStopped = false;
			const stopHandler = () => {
				hasBeenStopped = true;
				this._cleanup();
				this._resolver();
			};

			this._animation.once('STOPPED', stopHandler);
			this._animation.once('CANCELLED', stopHandler);

			// Check if this animation has any screen content
			const dofsInScreen = jibo.animate.dofs.SCREEN;
			const dofsInAnim = new MockDOFSet(this._animation.builder.dofNames);
			const dofsNotInAnim = dofsInScreen.minus(dofsInAnim);
			this._hasScreenDOFs = (dofsNotInAnim.getDOFs().length !== dofsInScreen.getDOFs().length);

			// TODO: Switch to system proposed in https://jira.jibo.com/browse/SB-2957 when available
			if (this._hasScreenDOFs) {
				jibo.face.eye.animation = this._animation;
			}

			if (this._options.configBuilder) {
				this._options.configBuilder(this._animation.builder);
			}

			// Here, if this animation has screen content, we center all of the screen DOFs
			if (!this._options.screenCenterOverride && this._hasScreenDOFs) {
				jibo.animate.centerRobot(dofsInScreen, null, () => {
					if (!hasBeenStopped) {
						this._playAndHandleInstance();
					}
				});
			} else {
				this._playAndHandleInstance();
			}
		});
	}

	_playAndHandleInstance() {
		const dofArbiter = this._options.jibo.dofArbiter;
		this._instance = dofArbiter.playAnimation(
			this._animation.builder, this._options.ownerInformation, this._options.dofOptions);
		if (this._instance && this._options.handleAnimation) {
			this._options.handleAnimation(this._instance);
		}
	}

	/**
	 * Stops playing animation
	 */
	stop() {
		if (this._instance) {
			this._instance.stop();
		}
	}

	_cleanup() {
		if (this._animation) {
			if (this._hasScreenDOFs) {
				this._options.jibo.face.eye.animation = null;
			}

			// Always destroy clean copies
			if (this._animation.isCopy) {
				this._animation.destroy();
				this._animation = null;
			}

			// If this animation was cached and we are not told to override the default unloading, then unload
			if (this._cache) {
				if (!this._options.overrideUnload) {
					this._options.jibo.loader.unload(this._alias);
				}
			}
			// If the animation was not cached and we are not told to override the default destroying, then destroy
			else if (!this._options.overrideDestroy && this._animation) {
				this._animation.destroy();
			}
		}

		this._animation = null;
		this._instance = null;
	}
}


export class PlaybackUtils {

	/**
	 * Creates a KeysPlayback object
	 * @param {KeysPlaybackOptions} options
	 * @returns {Promise<KeysPlayback>}
	 */
	static async createKeysPlayback(options: KeysPlaybackOptions): Promise<KeysPlayback> {
		const jibo = options.jibo;
		const PathUtils = jibo.utils.PathUtils;

		let assetPack = options.assetPack || '';
		if (options.animPath && options.animData) {
			return Promise.reject<KeysPlayback>(`Can't provide both 'animPath' and 'animData'`);
		}
		else if (!options.animPath && !options.animData) {
			return Promise.reject<KeysPlayback>(`Need to provide either 'animPath' and 'animData'`);
		}

		let animPath = options.animPath || '';
		let alias = PathUtils.setDefaultPath('animations', animPath);

		// If animation data is provided, then we don't cache
		const cache: string = options.animData ? null : options.cache;

		// If the animation exists in cache then reset it and return it
		if (cache) {
			let animation = jibo.loader.cached(alias, cache);
			if (animation) {
				animation = animation.getCleanCopy();
				return Promise.resolve(new KeysPlayback(animation, cache, alias, options));
			}
		}

		return new Promise<KeysPlayback>( (resolve, reject) => {
			let src = animPath;
			if (!path.isAbsolute(src)) {
				src = PathUtils.getAssetUri(alias, assetPack);
			}
			const root = options.rootPath || PathUtils.findRoot(src);

			jibo.loader.load({
				id: alias,
				cache: cache,
				data: options.animData,
				src: src,
				upload: true,
				root: root,
				type: 'keys',
				complete: (error, animation) => {
					if (error) {
						return reject(error);
					}
					resolve(animation);
				}
			});
		}).then( animation => {
			return new KeysPlayback(animation, cache, alias, options);
		});
	}
}
